const lines = $input.item.json.stdout.split('
');
const services = [];
for (const line of lines) {
  if (line.trim() === '') continue;
  const parts = line.split('|');
  if (parts.length === 2) {
    services.push({
      name: parts[0],
      status: parts[1]
    });
  }
}
return [{ json: { services: services } }];

const requiredServices = ['aura-redis', 'aura-neo4j', 'aura-chromadb', 'aura-n8n'];
const parsedServices = $input.item.json.services;

const failedServices = [];
let allHealthy = true;

for (const requiredService of requiredServices) {
  const foundService = parsedServices.find(s => s.name === requiredService);
  if (!foundService || !foundService.status.startsWith('Up ')) {
    allHealthy = false;
    failedServices.push(requiredService);
  }
}

const timestamp = new Date().toISOString();
let output = {};

if (allHealthy) {
  output = {
    status: 'HEALTHY',
    timestamp: timestamp
  };
} else {
  output = {
    status: 'DEGRADED',
    failedServices: failedServices,
    timestamp: timestamp
  };
}

return [{ json: output }];
